function normalizeDeck(d){const commanders=d.commanders?.length?d.commanders:(d.commanderCard?[d.commanderCard]:[]);return {...d,commanders,commanderCard:commanders[0]||null,commander:commanders.map(c=>c.name).join(' + '),colorIdentity:[...new Set(commanders.flatMap(c=>c.colorIdentity||d.colorIdentity||[]))]}}
