function normalizeRules(r){if(r.keys?.length&&typeof r.keys[0]==='string')r.keys=r.keys.map(name=>({name,terms:[name.toLowerCase()],keywords:[]}));const out={...structuredClone(DEFAULT_RULES),...r};out.tribeAliases={...structuredClone(DEFAULT_RULES.tribeAliases),...(r.tribeAliases||{})};out.keywordDefinitions={...structuredClone(DEFAULT_RULES.keywordDefinitions),...(r.keywordDefinitions||{})};out.bracketOverrides={...(r.bracketOverrides||{})};out.legalOverrides=r.legalOverrides||[];out.illegalOverrides=r.illegalOverrides||[];out.recommendedNonbasics=r.recommendedNonbasics||structuredClone(DEFAULT_RULES.recommendedNonbasics);return out}
