function renderHome(){setHeader('Commander Armies','Deck builder • v19 NO CACHE');const last=decks[0];app.innerHTML=`<section class="hero hero-command"><div class="hero-emblem">CA</div><div class="hero-copy"><span class="eyebrow">COMMANDER ARMIES</span><h2>Costruisci la tua armata</h2><p>${last?`Riprendi <strong>${esc(last.name)}</strong> oppure crea un nuovo esercito.`:'Scegli comandante, Tribe e Key. Costruisci un mazzo conforme al formato.'}</p><div class="hero-actions"><button id="newDeckBtn" class="primary">Nuovo mazzo</button>${last?'<button id="continueBtn" class="secondary">Continua ultimo mazzo</button>':''}</div></div></section><section class="section-heading"><div><span class="eyebrow">QUARTIER GENERALE</span><h2>Menu principale</h2></div><span class="version-pill">v19</span></section><section class="menu-grid visual-menu">${menu('⚔️','Builder','Crea e valida la tua armata','builder')}${menu('🛡️','I miei mazzi','Apri, duplica ed esporta','decks')}${menu('🔎','Archivio carte','Esplora il catalogo Magic','archive')}${menu('★','Collezione','Preferiti e carte possedute','collection')}${menu('📜','Regole','Regolamento e categorie legali','rules')}${menu('⇩','Importa lista','Carica una decklist esistente','import')}${menu('⎙','Esporta','Lista e scheda stampabile','print')}${menu('⚙','Impostazioni','Backup e preferenze','settings')}${menu('♜','Admin','Key, Evergreen e bracket','admin')}</section>`;app.querySelectorAll('[data-page]').forEach(b=>b.onclick=()=>nav(b.dataset.page));newDeckBtn.onclick=()=>{newDeck();autoSave();nav('builder')};if(last)continueBtn.onclick=()=>{state.currentDeck=structuredClone(last);nav('builder')}}
