function renderBuilder(){if(!state.currentDeck)newDeck();state.currentDeck=normalizeDeck(state.currentDeck);const d=state.currentDeck;setHeader('Builder',`${d.tribe||'Tribe'} · ${d.key||'Key'}`);const commanderCards=(d.commanders||[]).map((c,i)=>`<div class="commander-chip"><img src="${cardImage(c)}"><span><b>${esc(c.name)}</b><small>${esc((c.colorIdentity||[]).join('')||'Incolore')} · ${esc(c.setName||c.set||'')}</small></span><button class="secondary" data-commander-print="${i}">Edizione</button><button class="danger" data-remove-commander="${i}">×</button></div>`).join('');app.innerHTML=`<section class="panel builder-identity"><div class="form-grid two"><label>Nome mazzo<input id="deckName" value="${esc(d.name)}"></label><label>Comandante<div class="inline"><button id="chooseCommanderBtn" class="secondary wide" type="button">🔎 Scegli dalla lista dei comandanti</button></div></label><label>Tribe<select id="tribe">${rules.tribes.map(x=>opt(x,d.tribe)).join('')}</select></label><label>Key<select id="key">${keyNames().map(x=>opt(x,d.key)).join('')}</select></label></div>${commanderCards||'<p class="muted top-gap">Nessun comandante selezionato.</p>'}<p class="muted tiny top-gap">Identità di colore combinata: <b>${esc((d.colorIdentity||[]).join('')||'Incolore')}</b></p></section><section class="builder-layout builder-layout-v18"><div class="catalog-workspace"><aside class="panel catalog-filters"><div class="filter-head"><span class="eyebrow">FILTRI</span><button id="clearFiltersBtn" class="text-btn" type="button">Azzera</button></div><label>Cerca<input id="search" placeholder="Nome, tipo o testo"></label><button id="searchBtn" class="primary wide">Cerca nel database</button><label>Ordina<select id="sort"><option value="relevance">Rilevanza</option><option value="name">Nome A-Z</option><option value="cmc">Valore di mana</option><option value="price">Prezzo</option><option value="type">Tipo</option></select></label><div class="filter-section"><b>Tipo di carta</b><div class="filter-stack">${['All','Creature','Planeswalker','Artifact','Enchantment','Instant','Sorcery','Battle','Land'].map(t=>`<button data-type="${t}" class="${state.typeFilter===t?'active':''}">${typeIt(t)}</button>`).join('')}</div></div><div class="filter-section"><b>Motivo di legalità</b><div class="filter-stack">${[['all','Tutte'],['tribe','Tribe'],['key','Key'],['evergreen','Evergreen'],['commander','Comandante'],['choose-type','Scegli tipo']].map(([v,l])=>`<button data-cat="${v}" class="${state.categoryFilter===v?'active':''}">${l}</button>`).join('')}</div></div><div class="filter-section"><b>Visualizzazione</b><div class="segmented"><button id="listViewBtn" class="secondary">☰ Lista</button><button id="gridViewBtn" class="secondary">▦ Griglia</button></div></div><button id="mobileDeckBtn" class="secondary wide mobile-only">🗂 Apri mazzo</button></aside><div class="catalog-results"><div class="catalog-results-head"><div><span class="eyebrow">CATALOGO CARTE</span><h2>Carte disponibili</h2></div><span id="resultCount" class="badge">${state.results.length} risultati</span></div><p class="muted tiny">Aggiunta rapida con <b>＋</b>. Le carte già presenti sono evidenziate.</p><div id="catalog" class="catalog-grid"></div><button id="moreBtn" class="secondary wide hidden">Carica altri risultati</button></div></div><aside class="panel deck-panel"><div class="deck-panel-head"><div><span class="eyebrow">MAZZO ATTUALE</span><h2>${esc(d.name)}</h2></div><button id="closeDeckBtn" class="secondary mobile-only" type="button">Chiudi</button></div><div class="statline"><span class="stat">Carte: <b id="count">${deckCount(d)}</b>/100</span><span class="stat">Terre: <b id="landCount">${countType(d,'Land')}</b></span><span class="stat">Valore: <b id="deckValue">${formatPrice(deckPrice(d))}</b></span><span class="stat">Stato: <b id="validState">—</b></span></div><div class="button-row top-gap"><button id="landsBtn" class="primary">Terre consigliate</button><button id="validationBtn" class="secondary">Validazione</button><button id="suggestBtn" class="secondary">Suggerisci</button><button id="guideBtn" class="primary">Completa</button></div><div class="deck-tools top-gap"><label>Ordina mazzo<select id="deckSort"><option value="type" ${state.deckSort==='type'?'selected':''}>Tipo</option><option value="name" ${state.deckSort==='name'?'selected':''}>Nome</option><option value="cmc" ${state.deckSort==='cmc'?'selected':''}>Valore di mana</option><option value="color" ${state.deckSort==='color'?'selected':''}>Colore</option></select></label><label class="check compact"><input id="deckGroup" type="checkbox" ${state.deckGroup?'checked':''}> Raggruppa per tipo</label></div><div id="deckStats" class="deck-stats top-gap"></div><div id="deckList" class="deck-list top-gap"></div></aside></section>`;bindBuilder();document.querySelectorAll('[data-remove-commander]').forEach(b=>b.onclick=()=>removeCommander(Number(b.dataset.removeCommander)));document.querySelectorAll('[data-commander-print]').forEach(b=>b.onclick=()=>showPrintings(d.commanders[Number(b.dataset.commanderPrint)],{kind:'commander',index:Number(b.dataset.commanderPrint)}));drawCatalog();drawDeck()}
function bindBuilder(){deckName.oninput=e=>{state.currentDeck.name=e.target.value;document.querySelector('.deck-panel h2').textContent=e.target.value;markDirty()};deckName.onchange=autoSave;chooseCommanderBtn.onclick=openCommanderSelector;tribe.onchange=e=>{state.currentDeck.tribe=e.target.value;state.results=[];autoSave();renderBuilder()};key.onchange=e=>{state.currentDeck.key=e.target.value;state.results=[];autoSave();renderBuilder()};document.querySelectorAll('[data-type]').forEach(b=>b.onclick=()=>{state.typeFilter=b.dataset.type;renderBuilder()});document.querySelectorAll('[data-cat]').forEach(b=>b.onclick=()=>{state.categoryFilter=b.dataset.cat;state.results=[];renderBuilder()});searchBtn.onclick=()=>searchCards(false);search.onkeydown=e=>{if(e.key==='Enter')searchCards(false)};sort.onchange=drawCatalog;landsBtn.onclick=suggestLands;validationBtn.onclick=showDetailedValidation;suggestBtn.onclick=suggestCards;guideBtn.onclick=showDeckGuide;deckSort.onchange=e=>{state.deckSort=e.target.value;drawDeck()};deckGroup.onchange=e=>{state.deckGroup=e.target.checked;drawDeck()};gridViewBtn.onclick=()=>{prefs.catalogView='grid';persist();drawCatalog()};listViewBtn.onclick=()=>{prefs.catalogView='list';persist();drawCatalog()};clearFiltersBtn.onclick=()=>{state.typeFilter='All';state.categoryFilter='all';state.results=[];renderBuilder()};mobileDeckBtn.onclick=()=>toggleMobileDeck(true);closeDeckBtn.onclick=()=>toggleMobileDeck(false)}
function toggleMobileDeck(open){prefs.mobileDeckOpen=open;persist();document.querySelector('.deck-panel')?.classList.toggle('mobile-open',open);document.body.classList.toggle('deck-open',open)}
async function openCommanderSelector(){
  modalTitle.textContent='Scegli il comandante';
  modalBody.innerHTML=`<section class="commander-picker-controls">
    <label>Cerca per nome<input id="commanderSearchInput" placeholder="Es. Atraxa, Edgar, Giada…"></label>
    <label>Colori<select id="commanderColorFilter"><option value="">Tutti</option><option value="c">Incolore</option><option value="w">Bianco</option><option value="u">Blu</option><option value="b">Nero</option><option value="r">Rosso</option><option value="g">Verde</option><option value="wu">Azorius</option><option value="ub">Dimir</option><option value="br">Rakdos</option><option value="rg">Gruul</option><option value="gw">Selesnya</option><option value="wb">Orzhov</option><option value="ur">Izzet</option><option value="bg">Golgari</option><option value="rw">Boros</option><option value="gu">Simic</option><option value="wub">Esper</option><option value="ubr">Grixis</option><option value="brg">Jund</option><option value="rgw">Naya</option><option value="gwu">Bant</option><option value="wubrg">Cinque colori</option></select></label>
    <label>Ordina<select id="commanderOrder"><option value="edhrec">Popolarità EDHREC</option><option value="name">Nome</option><option value="released">Più recenti</option><option value="cmc">Valore di mana</option></select></label>
    <button id="commanderSearchBtn" class="primary" type="button">Mostra comandanti</button>
  </section><p class="muted tiny">Sono mostrate solo carte legali in Commander che possono essere il comandante.</p><div id="commanderResults" class="commander-picker-grid"><p class="muted">Premi “Mostra comandanti” per caricare la lista.</p></div>`;
  modal.classList.add('commander-modal');
  modal.showModal();
  const run=()=>loadCommanderChoices();
  commanderSearchBtn.onclick=run;
  commanderSearchInput.onkeydown=e=>{if(e.key==='Enter'){e.preventDefault();run()}};
  commanderColorFilter.onchange=run;
  commanderOrder.onchange=run;
  await loadCommanderChoices();
}
async function loadCommanderChoices(){
  const box=document.querySelector('#commanderResults');
  if(!box)return;
  const name=document.querySelector('#commanderSearchInput')?.value.trim()||'';
  const colors=document.querySelector('#commanderColorFilter')?.value||'';
  const order=document.querySelector('#commanderOrder')?.value||'edhrec';
  const q=['legal:commander','(t:"legendary creature" OR o:"can be your commander" OR t:background)'];
  if(name)q.push(name);
  if(colors==='c')q.push('id:c'); else if(colors)q.push(`id=${colors}`);
  box.innerHTML='<p class="muted">Caricamento comandanti…</p>';
  try{
    const data=await api(`https://api.scryfall.com/cards/search?unique=cards&order=${encodeURIComponent(order)}&q=${encodeURIComponent(q.join(' '))}`);
    const cards=(data.data||[]).filter(isCommander).map(simplifyCard);
    if(!cards.length){box.innerHTML='<p class="muted">Nessun comandante trovato con questi filtri.</p>';return}
    box.innerHTML=cards.map((c,i)=>`<article class="commander-choice"><img src="${cardImage(c)}" alt="${esc(c.name)}"><div><b>${esc(c.name)}</b><small>${esc(c.type)}</small><small>Colori: ${esc((c.colorIdentity||[]).join('')||'Incolore')}</small><button class="primary wide" data-pick-commander="${i}" type="button">Scegli</button></div></article>`).join('');
    box.querySelectorAll('[data-pick-commander]').forEach(b=>b.onclick=()=>selectCommanderFromList(cards[Number(b.dataset.pickCommander)]));
  }catch(e){box.innerHTML=`<p class="error">${esc(e.message)}</p>`}
}
function selectCommanderFromList(card){
  const current=state.currentDeck.commanders||[];
  if(current.some(c=>c.id===card.id)){alert('Questo comandante è già stato aggiunto.');return}
  if(current.length>=2){alert('Sono ammessi al massimo due comandanti.');return}
  if(current.length===1&&!commandersCompatible(current[0],card)){alert('I due comandanti non formano una combinazione legale.');return}
  state.currentDeck.commanders=[...current,card];
  syncCommanders(state.currentDeck);
  autoSave();
  modal.classList.remove('commander-modal');
  modal.close();
  renderBuilder();
  toast('Comandante selezionato');
}
async function findCommanderCard(){const name=commander.value.trim();if(!name)return;setBusy(true,'Cerco il comandante…');try{const data=await api(`https://api.scryfall.com/cards/named?fuzzy=${encodeURIComponent(name)}`);if(!isCommander(data))throw new Error('La carta trovata non può essere usata come comandante.');const card=simplifyCard(data),current=state.currentDeck.commanders||[];if(current.some(c=>c.id===card.id))throw new Error('Questo comandante è già stato aggiunto.');if(current.length>=2)throw new Error('Sono ammessi al massimo due comandanti.');if(current.length===1&&!commandersCompatible(current[0],card))throw new Error('I due comandanti non formano una combinazione legale (Partner, Background, Doctor’s Companion o abilità equivalente).');state.currentDeck.commanders=[...current,card];syncCommanders(state.currentDeck);autoSave();renderBuilder();toast('Comandante aggiunto')}catch(e){alert(e.message)}finally{setBusy(false)}}
function syncCommanders(d){d.commanderCard=d.commanders?.[0]||null;d.commander=(d.commanders||[]).map(c=>c.name).join(' + ');d.colorIdentity=[...new Set((d.commanders||[]).flatMap(c=>c.colorIdentity||[]))]}
function removeCommander(i){state.currentDeck.commanders.splice(i,1);syncCommanders(state.currentDeck);autoSave();renderBuilder()}
function commandersCompatible(a,b){const ta=normalizedName(a.oracle),tb=normalizedName(b.oracle);if(ta.includes('partner with'))return ta.includes(normalizedName(b.name));if(tb.includes('partner with'))return tb.includes(normalizedName(a.name));if(ta.includes('friends forever')&&tb.includes('friends forever'))return true;if(ta.includes("doctor's companion")&&/time lord doctor/i.test(b.type))return true;if(tb.includes("doctor's companion")&&/time lord doctor/i.test(a.type))return true;if(ta.includes('choose a background')&&/legendary enchantment — background/i.test(b.type))return true;if(tb.includes('choose a background')&&/legendary enchantment — background/i.test(a.type))return true;return /(^|\W)partner(\W|$)/i.test(a.oracle)&&/(^|\W)partner(\W|$)/i.test(b.oracle)}
function isCommander(c){const type=allType(c).toLowerCase(),text=allOracle(c).toLowerCase();return (type.includes('legendary creature')||type.includes('legendary enchantment — background')||text.includes('can be your commander'))&&c.legalities?.commander==='legal'}
function buildScryfallQuery(){const d=state.currentDeck,q=[];q.push('legal:commander');if(rules.excludeGameChangers&&rules.maxBracket<=2)q.push('-is:gamechanger');if(d.colorIdentity?.length)q.push(`id<=${d.colorIdentity.join('')}`);else if(d.commanderCard)q.push('id:c');const typed={Creature:'t:creature',Planeswalker:'t:planeswalker',Artifact:'t:artifact',Enchantment:'t:enchantment',Instant:'t:instant',Sorcery:'t:sorcery',Battle:'t:battle',Land:'t:land'}[state.typeFilter];if(typed)q.push(typed);const tribe=d.tribe,key=getKey(d.key);if(state.categoryFilter==='tribe')q.push(`(t:${quote(tribe)} OR o:${quote(tribe)})`);if(state.categoryFilter==='evergreen'&&rules.evergreen.length)q.push(`(${rules.evergreen.map(n=>`!${quote(n)}`).join(' OR ')})`);if(state.categoryFilter==='commander')q.push('o:commander');if(state.categoryFilter==='choose-type')q.push(`(${rules.chooseTypePhrases.map(p=>`o:${quote(p)}`).join(' OR ')})`);if(state.categoryFilter==='key'&&key){const terms=[...key.terms,...key.keywords];q.push(`(${terms.map(t=>`o:${quote(t)}`).join(' OR ')})`)}const text=document.querySelector('#search')?.value.trim();if(text)q.push(text.includes(':')?text:quote(text));return q.join(' ')}
async function searchCards(more=false){const query=buildScryfallQuery();setBusy(true,'Cerco le carte…');try{const url=more&&state.nextPage?state.nextPage:`https://api.scryfall.com/cards/search?order=edhrec&unique=cards&q=${encodeURIComponent(query)}`;const data=await api(url);const cards=(data.data||[]).map(simplifyCard).filter(c=>cardAllowed(c,state.currentDeck));state.results=more?[...state.results,...cards]:cards;state.nextPage=data.has_more?data.next_page:null;state.lastQuery=query;drawCatalog();moreBtn.classList.toggle('hidden',!state.nextPage);moreBtn.onclick=()=>searchCards(true)}catch(e){document.querySelector('#catalog').innerHTML=`<p class="error">${esc(e.message)}</p>`}finally{setBusy(false)}}
function drawCatalog(){const root=document.querySelector('#catalog');if(!root)return;root.classList.toggle('catalog-list',prefs.catalogView!=='grid');document.querySelector('#gridViewBtn')?.classList.toggle('active',prefs.catalogView==='grid');document.querySelector('#listViewBtn')?.classList.toggle('active',prefs.catalogView!=='grid');document.querySelector('.deck-panel')?.classList.toggle('mobile-open',prefs.mobileDeckOpen);document.body.classList.toggle('deck-open',prefs.mobileDeckOpen);let cards=[...state.results];const mode=document.querySelector('#sort')?.value;if(mode==='name')cards.sort((a,b)=>a.name.localeCompare(b.name));if(mode==='cmc')cards.sort((a,b)=>(a.cmc||0)-(b.cmc||0));if(mode==='price')cards.sort((a,b)=>(cardPrice(a)||999999)-(cardPrice(b)||999999));if(mode==='type')cards.sort((a,b)=>a.type.localeCompare(b.type));const countEl=document.querySelector('#resultCount');if(countEl)countEl.textContent=`${cards.length} risultati`;root.innerHTML='';if(!cards.length){root.innerHTML='<section class="panel empty"><b>Cerca nel database Magic</b><p class="muted">Scegli comandante, Tribe e Key, applica i filtri e avvia la ricerca.</p></section>';return}for(const c of cards){const reason=legalReasons(c,state.currentDeck),fav=favorites.includes(c.id),owned=collection[c.id]||0,inDeck=state.currentDeck.cards.find(x=>x.id===c.id),qty=inDeck?.qty||0;root.insertAdjacentHTML('beforeend',`<article class="card-tile compact-card ${qty?'in-deck':''}"><button class="card-preview" data-details="${c.id}" aria-label="Apri dettagli di ${esc(c.name)}"><img class="card-image" loading="lazy" src="${cardImage(c)}" alt="${esc(c.name)}"></button><div class="card-meta"><div class="card-title-line"><strong>${esc(c.name)}</strong>${qty?`<span class="deck-qty">Nel mazzo ${qty}×</span>`:''}</div><small>${esc(c.type)}</small><small>${esc(c.setName||c.set||'')} · ${formatPrice(cardPrice(c))}</small><div class="reason">${reason.slice(0,2).map(r=>`<span class="badge">${esc(r)}</span>`).join('')}</div><div class="quick-actions"><button class="secondary fav-btn" data-id="${c.id}" title="Preferiti">${fav?'★':'☆'}</button><button class="secondary details-btn" data-id="${c.id}">Dettagli</button>${qty?`<button class="secondary quick-minus" data-id="${c.id}" title="Rimuovi una copia">−</button>`:''}<button class="primary add-btn" data-id="${c.id}" title="Aggiungi al mazzo">＋</button></div></div></article>`)}root.querySelectorAll('.add-btn').forEach(b=>b.onclick=()=>{addCard(cards.find(c=>c.id===b.dataset.id));drawCatalog()});root.querySelectorAll('.quick-minus').forEach(b=>b.onclick=()=>{removeCard(b.dataset.id);drawCatalog()});root.querySelectorAll('.details-btn,.card-preview').forEach(b=>b.onclick=()=>showCard(cards.find(c=>c.id===(b.dataset.id||b.dataset.details))));root.querySelectorAll('.fav-btn').forEach(b=>b.onclick=()=>{toggleFavorite(cards.find(c=>c.id===b.dataset.id));drawCatalog()})}
function legalReasons(c,d){const reasons=[],name=normalizedName(c.name),text=expandedRulesText(c),type=normalizedName(c.type),aliases=tribeTerms(d.tribe),isCreature=type.includes('creature');if(rules.illegalOverrides.some(x=>normalizedName(x)===name))return [];if(rules.legalOverrides.some(x=>normalizedName(x)===name))reasons.push('Eccezione Admin');if(rules.evergreen.some(x=>normalizedName(x)===name))reasons.push('Evergreen');if(isCreature&&aliases.some(a=>new RegExp(`(?:—|\\b)\\s*${escapeRegExp(a)}\\b`,'i').test(c.type)))reasons.push('Creatura della Tribe');if(aliases.some(a=>a&&new RegExp(`\\b${escapeRegExp(a)}s?\\b`,'i').test(text)))reasons.push(isCreature?'Creatura che cita la Tribe':'Cita la Tribe');if(!isCreature&&rules.chooseTypePhrases.some(p=>text.includes(normalizedName(p))))reasons.push('Scegli tipo');if(!isCreature&&rules.commanderPhrases.some(p=>text.includes(normalizedName(p))))reasons.push('Comandante');if(!isCreature&&matchesKey(c,getKey(d.key)))reasons.push(`Key: ${d.key}`);if(type.includes('basic land'))reasons.push('Terra base');return [...new Set(reasons)]}
function matchesKey(c,key){if(!key)return false;const text=expandedRulesText(c);const needles=[...(key.terms||[]),...(key.keywords||[])].map(normalizedName);return needles.some(t=>t&&new RegExp(`\\b${escapeRegExp(t)}(?:s|ed|ing)?\\b`,'i').test(text))}
function escapeRegExp(s){return String(s).replace(/[.*+?^${}()|[\]\\]/g,'\\$&')}
function getKey(name){return rules.keys.find(k=>k.name===name)}
function markDirty(){if(state.page==='builder')pageSubtitle.textContent='Modifiche non ancora salvate'}
function autoSave(){if(prefs.autosave&&state.currentDeck){saveCurrentDeck();pageSubtitle.textContent='✓ Salvato automaticamente';setTimeout(()=>{if(state.page==='builder')pageSubtitle.textContent=`${state.currentDeck?.tribe||''} · ${state.currentDeck?.key||''}`},900)}}
function addCard(c,qty=1){const d=state.currentDeck,existing=d.cards.find(x=>x.id===c.id);const basic=c.type.toLowerCase().includes('basic land');if(existing){if(!basic){toast('Carta già presente');return}existing.qty=(existing.qty||1)+qty}else d.cards.push({...c,qty});drawDeck();autoSave();toast(`${c.name} aggiunta`)}
function primaryType(c){const t=c.type||'';for(const x of ['Creature','Planeswalker','Artifact','Enchantment','Instant','Sorcery','Battle','Land'])if(t.includes(x))return x;return 'Altro'}
function cardColorLabel(c){const ids=c.colorIdentity||[];return ids.length?ids.join(''):'C'}
function sortedDeckCards(d){const cards=[...d.cards];if(state.deckSort==='name')cards.sort((a,b)=>a.name.localeCompare(b.name));else if(state.deckSort==='cmc')cards.sort((a,b)=>(a.cmc||0)-(b.cmc||0)||a.name.localeCompare(b.name));else if(state.deckSort==='color')cards.sort((a,b)=>cardColorLabel(a).localeCompare(cardColorLabel(b))||a.name.localeCompare(b.name));else cards.sort((a,b)=>primaryType(a).localeCompare(primaryType(b))||a.name.localeCompare(b.name));return cards}
function deckCardRow(c){const status=cardValidation(c,state.currentDeck);return `<div class="deck-row quantity-row ${status.errors.length?'row-error':''}"><button class="card-link" data-details="${c.id}"><span>${esc(c.name)}<br><small class="muted">${esc(c.type)} · ${esc(c.set||'')} ${esc(c.collectorNumber||'')} · ${formatPrice(cardPrice(c))}</small></span></button><button class="secondary" data-edition="${c.id}">Edizione</button><div class="qty-control"><button class="secondary" data-minus="${c.id}">−</button><b>${c.qty||1}</b><button class="secondary" data-plus="${c.id}">＋</button></div><button class="danger" data-remove="${c.id}">✕</button></div>`}
function drawDeck(){const d=state.currentDeck,root=document.querySelector('#deckList');if(!root)return;count.textContent=deckCount(d);landCount.textContent=countType(d,'Land');if(document.querySelector('#deckValue'))deckValue.textContent=formatPrice(deckPrice(d));const validation=validateDeck(d);validState.textContent=validation.errors.length?'Da correggere':'Valido';validState.className=validation.errors.length?'error':'success';drawDeckStats(d);const cards=sortedDeckCards(d);let html='';if(state.deckGroup){const groups={};for(const c of cards)(groups[primaryType(c)]??=[]).push(c);for(const type of ['Creature','Planeswalker','Artifact','Enchantment','Instant','Sorcery','Battle','Land','Altro'])if(groups[type]?.length)html+=`<section class="deck-group"><h3>${typeIt(type)} <span>${groups[type].reduce((n,c)=>n+(c.qty||1),0)}</span></h3>${groups[type].map(deckCardRow).join('')}</section>`}else html=cards.map(deckCardRow).join('');root.innerHTML=html||'<p class="muted">Il mazzo è vuoto.</p>';root.querySelectorAll('[data-remove]').forEach(b=>b.onclick=()=>removeCard(b.dataset.remove));root.querySelectorAll('[data-plus]').forEach(b=>b.onclick=()=>changeQty(b.dataset.plus,1));root.querySelectorAll('[data-minus]').forEach(b=>b.onclick=()=>changeQty(b.dataset.minus,-1));root.querySelectorAll('[data-details]').forEach(b=>b.onclick=()=>showCard(d.cards.find(c=>c.id===b.dataset.details)));root.querySelectorAll('[data-edition]').forEach(b=>b.onclick=()=>showPrintings(d.cards.find(c=>c.id===b.dataset.edition),{kind:'deck'}));if(validation.errors.length)root.insertAdjacentHTML('afterbegin',`<div class="validation-box"><b>${validation.errors.length} problemi rilevati</b>${validation.errors.slice(0,4).map(e=>`<p>⚠ ${esc(e)}</p>`).join('')}${validation.errors.length>4?'<p class="muted tiny">Apri “Validazione dettagliata” per vedere tutto.</p>':''}</div>`)}
function changeQty(id,delta){const c=state.currentDeck.cards.find(x=>x.id===id);if(!c)return;const basic=c.type.toLowerCase().includes('basic land');if(!basic&&delta>0){toast('In Commander è consentita una sola copia');return}c.qty=Math.max(0,(c.qty||1)+delta);if(c.qty===0)state.currentDeck.cards=state.currentDeck.cards.filter(x=>x.id!==id);drawDeck()}
function drawDeckStats(d){const root=document.querySelector('#deckStats');if(!root)return;const types=['Creature','Artifact','Enchantment','Instant','Sorcery','Planeswalker','Battle','Land'];const mana=[0,0,0,0,0,0,0,0];for(const c of d.cards){if(c.type.includes('Land'))continue;const i=Math.min(7,Math.floor(c.cmc||0));mana[i]+=(c.qty||1)}const typeHtml=types.map(t=>`<span>${typeIt(t)} <b>${countContainsType(d,t)}</b></span>`).join('');const max=Math.max(1,...mana);const curve=mana.map((n,i)=>`<div class="curve-col"><div class="curve-bar" style="height:${Math.max(4,Math.round(n/max*72))}px"></div><b>${n}</b><small>${i===7?'7+':i}</small></div>`).join('');const nonlandCards=d.cards.filter(c=>!c.type.includes('Land'));const totalNonlands=nonlandCards.reduce((n,c)=>n+(c.qty||1),0);const avg=totalNonlands?nonlandCards.reduce((n,c)=>n+(c.cmc||0)*(c.qty||1),0)/totalNonlands:0;const sources=manaWeights(d.cards);root.innerHTML=`<details><summary>Statistiche del mazzo</summary><div class="type-stats">${typeHtml}<span>CMC medio <b>${avg.toFixed(2)}</b></span><span>Fonti mana <b>${Object.entries(sources).filter(([,n])=>n).map(([c,n])=>c+': '+n).join(' · ')||'—'}</b></span></div><h4>Curva di mana</h4><div class="mana-curve">${curve}</div></details>`}
function countContainsType(d,t){return d.cards.reduce((n,c)=>n+(c.type.includes(t)?(c.qty||1):0),0)}
function removeCard(id){const c=state.currentDeck.cards.find(x=>x.id===id);if((c?.qty||1)>1)c.qty--;else state.currentDeck.cards=state.currentDeck.cards.filter(x=>x.id!==id);drawDeck();autoSave()}
function cardValidation(c,d){const errors=[],reasons=legalReasons(c,d);if(c.legalities?.commander&&c.legalities.commander!=='legal')errors.push('Non legale in Commander');if(cardBracket(c)>rules.maxBracket)errors.push(`Bracket ${cardBracket(c)} superiore al massimo ${rules.maxBracket}`);if(rules.illegalOverrides.some(x=>normalizedName(x)===normalizedName(c.name)))errors.push('Esclusa manualmente dall’Admin');if(d.colorIdentity?.length&&!c.colorIdentity.every(x=>d.colorIdentity.includes(x)))errors.push('Fuori dall’identità di colore');if(!reasons.length)errors.push('Non soddisfa Tribe, Key o categorie speciali');return {errors,reasons}}
function validateDeck(d){const errors=[];if(!(d.commanders||[]).length)errors.push('Comandante non verificato');if((d.commanders||[]).length===2&&!commandersCompatible(d.commanders[0],d.commanders[1]))errors.push('La coppia di comandanti non è compatibile');if(deckCount(d)!==100)errors.push(`Il mazzo contiene ${deckCount(d)} carte anziché 100`);const seen=new Set();for(const c of d.cards){const basic=c.type.toLowerCase().includes('basic land');if(!basic&&seen.has(c.id))errors.push(`${c.name} compare più volte`);seen.add(c.id);if(!basic&&(c.qty||1)>1)errors.push(`${c.name}: quantità ${c.qty}, ma Commander consente una copia`);for(const e of cardValidation(c,d).errors)errors.push(`${c.name}: ${e}`)}return {errors}}
function showDetailedValidation(){const d=state.currentDeck,v=validateDeck(d);const rows=[];for(const cmd of (d.commanders||[]))rows.push(`<div class="validation-row ok"><b>${esc(cmd.name)}</b><span>Comandante verificato · ${esc(cmd.setName||cmd.set||'')}</span></div>`);for(const c of sortedDeckCards(d)){const x=cardValidation(c,d);rows.push(`<div class="validation-row ${x.errors.length?'bad':'ok'}"><b>${esc(c.name)}</b><span>${x.errors.length?x.errors.map(esc).join(' · '):x.reasons.map(esc).join(' · ')}</span></div>`)}modalTitle.textContent='Validazione dettagliata';modalBody.innerHTML=`<div class="validation-summary ${v.errors.length?'bad':'ok'}"><b>${v.errors.length?`${v.errors.length} problemi da correggere`:'Mazzo conforme'}</b><span>${deckCount(d)}/100 carte · ${countType(d,'Land')} terre</span></div><div class="validation-list">${rows.join('')||'<p class="muted">Nessuna carta nel mazzo.</p>'}</div>`;modal.showModal()}
function deckCount(d){return d.cards.reduce((n,c)=>n+(c.qty||1),(d.commanders||[]).length)}function countType(d,t){return d.cards.reduce((n,c)=>n+(c.type.startsWith(t)?(c.qty||1):0),0)}
function suggestLands(){const d=state.currentDeck,current=countType(d,'Land'),nonlandCards=d.cards.filter(c=>!c.type.includes('Land')),nonlands=nonlandCards.reduce((n,c)=>n+(c.qty||1),0),avg=nonlands?nonlandCards.reduce((n,c)=>n+(c.cmc||0)*(c.qty||1),0)/nonlands:3,ramp=d.cards.reduce((n,c)=>n+(/add \{|search your library for (?:a|up to one) (?:basic )?land|treasure token/i.test(expandedRulesText(c))?(c.qty||1):0),0);let recommended=36;if(avg>=3.8)recommended++;if(avg<=2.5)recommended--;if(ramp>=10)recommended--;if(ramp<=4&&avg>=3.2)recommended++;recommended=Math.max(34,Math.min(39,recommended));const missing=Math.max(0,recommended-current),weights=manaWeights(d.cards),colors=(d.colorIdentity||[]);modalTitle.textContent='Terre consigliate';modalBody.innerHTML=`<p>Terre presenti: <b>${current}</b>. Consiglio: <b>${recommended}</b>.</p><p class="muted tiny">Calcolo basato su CMC medio ${avg.toFixed(2)}, ${ramp} carte di ramp e distribuzione dei simboli di mana.</p><p>Da aggiungere: <b>${missing}</b>.</p><div class="mana-split">${colors.map(c=>`<span>${c}: ${Math.round((weights[c]||1)/sumWeights(weights,colors)*missing)}</span>`).join(' ')||'<span>Solo terre incolori</span>'}</div><div class="button-row top-gap"><button id="addBasics" class="primary" ${missing?'':'disabled'}>Solo terre base</button><button id="addBalanced" class="secondary" ${missing?'':'disabled'}>Base bilanciata</button></div><p class="muted tiny">La base bilanciata prova prima le terre non base configurate dall’Admin e completa il resto con terre base.</p>`;modal.showModal();addBasics.onclick=async()=>{modal.close();await addRecommendedBasics(missing,weights,colors)};addBalanced.onclick=async()=>{modal.close();await addBalancedLands(missing,weights,colors)}}
async function addBalancedLands(missing,weights,colors){setBusy(true,'Creo la base di mana…');let left=missing;for(const name of rules.recommendedNonbasics){if(left<=0)break;try{const raw=await api(`https://api.scryfall.com/cards/named?exact=${encodeURIComponent(name)}`);const c=simplifyCard(raw);if(c.type.toLowerCase().includes('land')&&!state.currentDeck.cards.some(x=>x.id===c.id)&&cardAllowed(c,state.currentDeck)){addCard(c);left--}}catch{}await delay(60)}if(left>0)await addRecommendedBasics(left,weights,colors);setBusy(false);drawDeck()}
function manaWeights(cards){const w={W:0,U:0,B:0,R:0,G:0};for(const c of cards){const cost=c.manaCost||'';for(const k of Object.keys(w))w[k]+=(cost.match(new RegExp(k,'g'))||[]).length}return w}function sumWeights(w,colors){return colors.reduce((n,c)=>n+(w[c]||1),0)||1}
async function addRecommendedBasics(missing,w,colors){if(!missing)return;setBusy(true,'Aggiungo le terre…');try{const active=colors.length?colors:['C'];let assigned=0;for(let i=0;i<active.length;i++){const color=active[i];if(color==='C')continue;const qty=i===active.length-1?missing-assigned:Math.round((w[color]||1)/sumWeights(w,active)*missing);assigned+=qty;if(qty<=0)continue;const card=await api(`https://api.scryfall.com/cards/named?exact=${encodeURIComponent(BASIC_LANDS[color])}`);addCard(simplifyCard(card),qty)}renderBuilder()}catch(e){alert(e.message)}finally{setBusy(false)}}
function saveCurrentDeck(){const d=state.currentDeck;d.updatedAt=Date.now();const i=decks.findIndex(x=>x.id===d.id);if(i>=0)decks[i]=structuredClone(d);else decks.unshift(structuredClone(d));decks.sort((a,b)=>b.updatedAt-a.updatedAt);persist()}
function renderDecks(){setHeader('I miei mazzi',`${decks.length} salvati`);app.innerHTML=`<section class="list">${decks.map(d=>`<article class="list-item"><img src="${d.commanderCard?cardImage(d.commanderCard):placeholder()}" alt=""><div><b>${esc(d.name)}</b><p class="muted">${esc(d.tribe)} · ${esc(d.key)} · ${deckCount(d)} carte</p></div><div class="stack"><button class="primary" data-open="${d.id}">Apri</button><button class="secondary" data-copy="${d.id}">Duplica</button><button class="danger" data-del="${d.id}">Elimina</button></div></article>`).join('')||'<section class="panel"><p>Nessun mazzo salvato.</p></section>'}</section>`;app.querySelectorAll('[data-open]').forEach(b=>b.onclick=()=>{state.currentDeck=structuredClone(decks.find(d=>d.id===b.dataset.open));nav('builder')});app.querySelectorAll('[data-copy]').forEach(b=>b.onclick=()=>{const d=structuredClone(decks.find(x=>x.id===b.dataset.copy));d.id=crypto.randomUUID();d.name+=' (copia)';d.updatedAt=Date.now();decks.unshift(d);persist();renderDecks()});app.querySelectorAll('[data-del]').forEach(b=>b.onclick=()=>{if(confirm('Eliminare il mazzo?')){decks=decks.filter(d=>d.id!==b.dataset.del);persist();renderDecks()}})}
function renderArchive(){setHeader('Archivio carte','Catalogo Magic');app.innerHTML=`<section class="panel"><div class="form-grid search-grid"><label>Ricerca Scryfall<input id="archiveSearch" placeholder="es. Vampire, t:artifact, o:commander"></label><label>Tipo<select id="archiveType">${['All','Creature','Planeswalker','Artifact','Enchantment','Instant','Sorcery','Battle','Land'].map(t=>`<option value="${t}">${typeIt(t)}</option>`).join('')}</select></label><button id="archiveBtn" class="primary">Cerca</button></div></section><div id="archiveGrid" class="catalog-grid"></div>`;archiveBtn.onclick=searchArchive;archiveSearch.onkeydown=e=>{if(e.key==='Enter')searchArchive()};drawArchive()}
async function searchArchive(){let q='legal:commander';if(rules.excludeGameChangers&&rules.maxBracket<=2)q+=' -is:gamechanger';const t=archiveType.value;if(t!=='All')q+=` t:${t.toLowerCase()}`;if(archiveSearch.value.trim())q+=' '+archiveSearch.value.trim();setBusy(true,'Cerco…');try{const data=await api(`https://api.scryfall.com/cards/search?unique=cards&order=name&q=${encodeURIComponent(q)}`);state.archiveResults=(data.data||[]).map(simplifyCard);drawArchive()}catch(e){archiveGrid.innerHTML=`<p class="error">${esc(e.message)}</p>`}finally{setBusy(false)}}
function drawArchive(){const root=document.querySelector('#archiveGrid');if(!root)return;root.innerHTML=state.archiveResults.map(c=>`<article class="card-tile"><img class="card-image" loading="lazy" src="${cardImage(c)}"><div class="card-meta"><strong>${esc(c.name)}</strong><small>${esc(c.type)}</small><button class="secondary wide" data-view="${c.id}">Dettagli</button></div></article>`).join('')||'<section class="panel empty">Cerca una carta o una categoria.</section>';root.querySelectorAll('[data-view]').forEach(b=>b.onclick=()=>showCard(state.archiveResults.find(c=>c.id===b.dataset.view)))}
function toggleFavorite(c){savedCards[c.id]=c;favorites=favorites.includes(c.id)?favorites.filter(x=>x!==c.id):[...favorites,c.id];persist();drawCatalog();toast(favorites.includes(c.id)?'Aggiunta ai preferiti':'Rimossa dai preferiti')}
function changeOwned(c,delta){savedCards[c.id]=c;collection[c.id]=Math.max(0,(collection[c.id]||0)+delta);if(!collection[c.id])delete collection[c.id];persist();drawCatalog();toast(`Copie possedute: ${collection[c.id]||0}`)}

function roleCount(d,role){return d.cards.reduce((n,c)=>n+(role.test(c)?(c.qty||1):0),0)}
function showDeckGuide(){
  const d=state.currentDeck;
  const rows=GUIDE_ROLES.map(r=>{const n=roleCount(d,r),ok=n>=r.target;return `<article class="guide-row ${ok?'guide-ok':''}"><div><b>${esc(r.label)}</b><small>${n} / ${r.target} consigliate</small></div><div class="guide-progress"><span style="width:${Math.min(100,Math.round(n/r.target*100))}%"></span></div><button class="${ok?'secondary':'primary'}" data-guide="${r.id}">${ok?'Esplora':'Trova carte'}</button></article>`}).join('');
  const total=deckCount(d),missing=Math.max(0,100-total);
  modalTitle.textContent='Procedura guidata';
  modalBody.innerHTML=`<p>Il mazzo contiene <b>${total}/100</b> carte. Mancano <b>${missing}</b> carte.</p><p class="muted tiny">I valori sono linee guida, non obblighi. Ogni risultato viene comunque filtrato per identità di colore, Tribe, Key, bracket e regole Admin.</p><div class="guide-list">${rows}</div><div class="button-row top-gap"><button id="guideLands" class="secondary">Calcola terre</button><button id="guideValidate" class="primary">Controlla il mazzo</button></div>`;
  modal.showModal();
  modalBody.querySelectorAll('[data-guide]').forEach(b=>b.onclick=()=>{const role=GUIDE_ROLES.find(r=>r.id===b.dataset.guide);modal.close();loadRoleSuggestions(role)});
  guideLands.onclick=()=>{modal.close();suggestLands()};
  guideValidate.onclick=()=>{modal.close();showDetailedValidation()};
}
async function loadRoleSuggestions(role){
  if(!role)return;const d=state.currentDeck;
  let q=`legal:commander ${role.query}`;
  if(rules.excludeGameChangers&&rules.maxBracket<=2)q+=' -is:gamechanger';
  if((d.colorIdentity||[]).length)q+=` id<=${d.colorIdentity.join('')}`;else q+=' id:c';
  setBusy(true,`Cerco: ${role.label}…`);
  try{
    const data=await api(`https://api.scryfall.com/cards/search?order=edhrec&unique=cards&q=${encodeURIComponent(q)}`);
    state.results=(data.data||[]).map(simplifyCard).filter(c=>cardAllowed(c,d)&&role.test(c)&&!d.cards.some(x=>x.id===c.id)).slice(0,40);
    state.typeFilter='All';state.categoryFilter='all';drawCatalog();
    if(!state.results.length)alert(`Non ho trovato carte aggiuntive per “${role.label}” che rispettino tutti i vincoli attuali.`);else toast(`${role.label}: ${state.results.length} suggerimenti`);
  }catch(e){alert(e.message)}finally{setBusy(false)}
}

async function suggestCards(){if(!state.currentDeck)return;const d=state.currentDeck,needs=[];if(countContainsType(d,'Land')<34)needs.push('t:land');if(countContainsType(d,'Creature')<22)needs.push('t:creature');if(countContainsType(d,'Instant')+countContainsType(d,'Sorcery')<12)needs.push('(t:instant OR t:sorcery)');const focus=needs[0]||'';const q=[focus,d.tribe?`(t:creature ${quote(d.tribe)} OR o:${quote(d.tribe)})`:'',getKey(d.key)?.terms?.[0]?`o:${quote(getKey(d.key).terms[0])}`:''].filter(Boolean).join(' ');setBusy(true,'Cerco suggerimenti…');try{const data=await api(`https://api.scryfall.com/cards/search?order=edhrec&unique=cards&q=${encodeURIComponent(q)}`);state.results=(data.data||[]).map(simplifyCard).filter(c=>cardAllowed(c,d)&&!d.cards.some(x=>x.id===c.id)).slice(0,30);drawCatalog();toast('Suggerimenti caricati')}catch(e){alert(e.message)}finally{setBusy(false)}}
function renderCollection(){setHeader('Collezione',`${favorites.length} preferiti · ${Object.values(collection).reduce((a,b)=>a+b,0)} copie`);const all=[...Object.values(savedCards),...decks.flatMap(d=>[...(d.commanders||[]),...d.cards])];const uniq=[...new Map(all.map(c=>[c.id,c])).values()].filter(c=>state.collectionFilter==='favorites'?favorites.includes(c.id):state.collectionFilter==='owned'?(collection[c.id]||0)>0:(favorites.includes(c.id)||(collection[c.id]||0)>0));app.innerHTML=`<div class="toolbar">${[['all','Tutto'],['favorites','Preferiti'],['owned','Possedute']].map(([v,l])=>`<button data-cfilter="${v}" class="${state.collectionFilter===v?'active':''}">${l}</button>`).join('')}</div><div class="catalog-grid">${uniq.map(c=>`<article class="card-tile"><img class="card-image" src="${cardImage(c)}"><div class="card-meta"><strong>${esc(c.name)}</strong><small>${favorites.includes(c.id)?'★ Preferita':''} ${collection[c.id]?`· ${collection[c.id]} copie`:''}</small><div class="card-actions"><button class="secondary" data-cfav="${c.id}">${favorites.includes(c.id)?'Rimuovi ★':'Aggiungi ☆'}</button><button class="secondary" data-cminus="${c.id}">−</button><button class="primary" data-cplus="${c.id}">＋</button></div></div></article>`).join('')||'<section class="panel empty">Nessuna carta salvata. Aggiungi preferiti o copie possedute dal Builder.</section>'}</div>`;document.querySelectorAll('[data-cfilter]').forEach(b=>b.onclick=()=>{state.collectionFilter=b.dataset.cfilter;renderCollection()});document.querySelectorAll('[data-cfav]').forEach(b=>b.onclick=()=>{const c=uniq.find(x=>x.id===b.dataset.cfav);toggleFavorite(c);renderCollection()});document.querySelectorAll('[data-cplus]').forEach(b=>b.onclick=()=>{const c=uniq.find(x=>x.id===b.dataset.cplus);changeOwned(c,1);renderCollection()});document.querySelectorAll('[data-cminus]').forEach(b=>b.onclick=()=>{const c=uniq.find(x=>x.id===b.dataset.cminus);changeOwned(c,-1);renderCollection()})}
function renderRules(){setHeader('Regole','Commander Armies');app.innerHTML=`<section class="panel prose"><h2>Legalità delle carte</h2><ol><li>Evergreen.</li><li>Creature della Tribe scelta.</li><li>Creature di altro tipo che citano la Tribe.</li><li>Non creature con “scegli un tipo di creatura”.</li><li>Non creature che citano la Tribe.</li><li>Non creature che citano il comandante.</li><li>Non creature che soddisfano la Key scelta.</li></ol><h2>Bracket</h2><p>Il limite configurato è <b>${rules.maxBracket}</b>. ${rules.excludeGameChangers?'I Game Changer sono esclusi.':''}</p><h2>Versione database</h2><p>${esc(rules.version)}</p></section>`}
function renderAdmin(){setHeader('Admin','Configurazione formato');const tabs=['Collaudo','Collaudo liste','Evergreen','Key','Tribe','Bracket','Eccezioni','Terre','Frasi speciali'];app.innerHTML=`<div class="admin-tabs">${tabs.map(t=>`<button class="${state.adminTab===t?'primary':'secondary'}" data-tab="${t}">${t}</button>`).join('')}</div><section id="adminBody" class="panel"></section>`;app.querySelectorAll('[data-tab]').forEach(b=>b.onclick=()=>{state.adminTab=b.dataset.tab;renderAdmin()});drawAdminBody()}
function drawAdminBody(){const b=adminBody;if(state.adminTab==='Collaudo'){drawAdminTester(b);return}if(state.adminTab==='Collaudo liste'){drawAdminBatchTester(b);return}if(state.adminTab==='Evergreen')listEditor(b,'Carte Evergreen',rules.evergreen,v=>rules.evergreen=v);if(state.adminTab==='Tribe'){b.innerHTML='<h2>Tribe e alias</h2><div id="tribeListRoot"></div><h3>Alias della Tribe</h3><label>Tribe<select id="aliasTribe">${rules.tribes.map(x=>`<option>${esc(x)}</option>`).join("")}</select></label><div id="aliasRoot" class="top-gap"></div>';listEditor(tribeListRoot,'',rules.tribes,v=>rules.tribes=v);const drawAliases=()=>listEditor(aliasRoot,'',rules.tribeAliases[aliasTribe.value]||[aliasTribe.value],v=>rules.tribeAliases[aliasTribe.value]=v);aliasTribe.onchange=drawAliases;drawAliases()}if(state.adminTab==='Key')keyEditor(b);if(state.adminTab==='Bracket'){b.innerHTML=`<h2>Bracket massimo</h2><label>Valore consentito<input id="maxBracket" type="number" min="1" max="5" value="${rules.maxBracket}"></label><label class="check"><input id="excludeGC" type="checkbox" ${rules.excludeGameChangers?'checked':''}> Escludi Game Changer per Bracket 1–2</label>`;maxBracket.onchange=e=>{rules.maxBracket=Number(e.target.value);persist()};excludeGC.onchange=e=>{rules.excludeGameChangers=e.target.checked;persist()}}if(state.adminTab==='Eccezioni'){b.innerHTML='<h2>Eccezioni manuali</h2><p class="muted">Le carte ammesse forzatamente restano soggette a identità di colore e bracket. Le escluse sono sempre illegali.</p><h3>Ammesse</h3><div id="legalList"></div><h3>Escluse</h3><div id="illegalList"></div><h3>Bracket per carta</h3><div id="bracketList"></div>';listEditor(legalList,'',rules.legalOverrides,v=>rules.legalOverrides=v);listEditor(illegalList,'',rules.illegalOverrides,v=>rules.illegalOverrides=v);objectEditor(bracketList,rules.bracketOverrides,v=>rules.bracketOverrides=v,'Nome carta','Bracket')}if(state.adminTab==='Terre'){b.innerHTML='<h2>Terre non base consigliate</h2><p class="muted">Devono essere Evergreen o comunque legali per le regole selezionate.</p><div id="landAdminList"></div>';listEditor(landAdminList,'',rules.recommendedNonbasics,v=>rules.recommendedNonbasics=v)}if(state.adminTab==='Frasi speciali'){b.innerHTML='<h2>Frasi speciali</h2><h3>Comandante</h3><div id="cmdList"></div><h3>Scegli tipo</h3><div id="typeList"></div>';listEditor(cmdList,'',rules.commanderPhrases,v=>rules.commanderPhrases=v);listEditor(typeList,'',rules.chooseTypePhrases,v=>rules.chooseTypePhrases=v)}}


async function drawAdminBatchTester(root){
  if(!state.adminBatchTribe)state.adminBatchTribe=rules.tribes[0]||'';
  if(!state.adminBatchKey)state.adminBatchKey=keyNames()[0]||'';
  root.innerHTML=`<h2>Collaudo liste e mazzi</h2><p class="muted">Analizza in blocco un mazzo salvato oppure incolla una lista. Ogni carta mostra la diagnosi e può essere corretta senza uscire dalla pagina.</p><div class="form-grid two"><label>Mazzo salvato<select id="batchDeck"><option value="">— Scegli un mazzo —</option>${decks.map(d=>`<option value="${d.id}">${esc(d.name)}</option>`).join('')}</select></label><label>Tribe<select id="batchTribe">${rules.tribes.map(x=>opt(x,state.adminBatchTribe)).join('')}</select></label><label>Key<select id="batchKey">${keyNames().map(x=>opt(x,state.adminBatchKey)).join('')}</select></label><label class="check"><input id="batchOnlyIssues" type="checkbox" ${state.adminBatchOnlyIssues?'checked':''}> Mostra solo carte problematiche</label></div><label class="top-gap">Lista da analizzare<textarea id="batchInput" placeholder="1 Sol Ring\n1 Arcane Signet\n1 Nome carta..."></textarea></label><div class="button-row top-gap"><button id="batchLoadDeck" class="secondary">Carica mazzo salvato</button><button id="batchAnalyze" class="primary">Analizza lista</button><button id="batchClear" class="danger">Svuota</button></div><div id="batchSummary" class="top-gap"></div><div id="batchResults" class="batch-results top-gap"></div>`;
  batchTribe.onchange=e=>{state.adminBatchTribe=e.target.value;drawAdminBatchResults()};
  batchKey.onchange=e=>{state.adminBatchKey=e.target.value;drawAdminBatchResults()};
  batchOnlyIssues.onchange=e=>{state.adminBatchOnlyIssues=e.target.checked;drawAdminBatchResults()};
  batchLoadDeck.onclick=()=>{const d=decks.find(x=>x.id===batchDeck.value);if(!d)return alert('Seleziona un mazzo.');state.adminBatchTribe=d.tribe||state.adminBatchTribe;state.adminBatchKey=d.key||state.adminBatchKey;state.adminBatchCards=[...(d.commanders||[]),...(d.cards||[])];drawAdminBatchTester(root);drawAdminBatchResults()};
  batchAnalyze.onclick=runAdminBatchAnalysis;
  batchClear.onclick=()=>{state.adminBatchCards=[];batchInput.value='';drawAdminBatchResults()};
  drawAdminBatchResults();
}
async function runAdminBatchAnalysis(){
  const lines=batchInput.value.split(/\r?\n/).map(parseLine).filter(Boolean);if(!lines.length)return alert('Inserisci almeno una carta valida.');
  batchResults.innerHTML='<p class="muted">Caricamento e analisi delle carte…</p>';const cards=[];
  for(let i=0;i<lines.length;i++){const item=lines[i];try{const raw=await api(`https://api.scryfall.com/cards/named?exact=${encodeURIComponent(item.name)}`);const c=simplifyCard(raw);c.qty=item.qty;savedCards[c.id]=c;cards.push(c)}catch(e){cards.push({id:`missing-${i}`,name:item.name,qty:item.qty,type:'',oracle:'',colorIdentity:[],keywords:[],legalities:{commander:'not_legal'},image:'',loadError:e.message})}await delay(70)}
  state.adminBatchCards=cards;persist();drawAdminBatchResults();
}
function adminBatchDeck(){return {tribe:state.adminBatchTribe,key:state.adminBatchKey,colorIdentity:[],cards:[],commanders:[]}}
function drawAdminBatchResults(){
  const root=document.querySelector('#batchResults'),summary=document.querySelector('#batchSummary');if(!root||!summary)return;const d=adminBatchDeck();let rows=(state.adminBatchCards||[]).map(c=>({c,v:c.loadError?{errors:[`Carta non trovata: ${c.loadError}`],reasons:[]}:cardValidation(c,d)}));const total=rows.length,issues=rows.filter(x=>x.v.errors.length).length,legal=total-issues;summary.innerHTML=total?`<div class="statline"><span class="stat">Carte: <b>${total}</b></span><span class="stat success">Legali: <b>${legal}</b></span><span class="stat error">Problematiche: <b>${issues}</b></span></div>`:'<p class="muted">Nessuna lista caricata.</p>';
  if(state.adminBatchOnlyIssues)rows=rows.filter(x=>x.v.errors.length);
  root.innerHTML=rows.map(({c,v},i)=>`<article class="batch-card ${v.errors.length?'batch-bad':'batch-ok'}"><img src="${cardImage(c)}" alt=""><div><div class="batch-title"><b>${esc(c.name)}</b><span class="badge">${c.qty||1}×</span></div><small class="muted">${esc(c.type||'Carta non riconosciuta')}</small><p class="${v.errors.length?'error':'success'}">${esc(v.errors.length?v.errors.join(' · '):(v.reasons.join(' · ')||'Legale'))}</p><div class="button-row"><button class="secondary" data-batch-action="legal" data-name="${esc(c.name)}">${hasRuleName(rules.legalOverrides,c.name)?'Rimuovi ammissione':'Ammetti'}</button><button class="secondary" data-batch-action="evergreen" data-name="${esc(c.name)}">${hasRuleName(rules.evergreen,c.name)?'Rimuovi Evergreen':'Evergreen'}</button><button class="danger" data-batch-action="illegal" data-name="${esc(c.name)}">${hasRuleName(rules.illegalOverrides,c.name)?'Rimuovi esclusione':'Escludi'}</button><button class="secondary" data-batch-detail="${i}">Dettagli</button></div></div></article>`).join('')||'<p class="muted">Nessuna carta da mostrare con il filtro attuale.</p>';
  root.querySelectorAll('[data-batch-action]').forEach(btn=>btn.onclick=()=>{toggleRuleName(btn.dataset.batchAction,btn.dataset.name);drawAdminBatchResults()});
  root.querySelectorAll('[data-batch-detail]').forEach(btn=>btn.onclick=()=>{const item=rows[Number(btn.dataset.batchDetail)];if(item)showBatchDiagnostic(item.c,d)});
}
function hasRuleName(arr,name){return arr.some(x=>normalizedName(x)===normalizedName(name))}
function toggleRuleName(kind,name){const map={legal:'legalOverrides',illegal:'illegalOverrides',evergreen:'evergreen'},key=map[kind],arr=rules[key];rules[key]=hasRuleName(arr,name)?arr.filter(x=>normalizedName(x)!==normalizedName(name)):[...arr,name];if(kind==='legal')rules.illegalOverrides=rules.illegalOverrides.filter(x=>normalizedName(x)!==normalizedName(name));if(kind==='illegal')rules.legalOverrides=rules.legalOverrides.filter(x=>normalizedName(x)!==normalizedName(name));persist()}
function showBatchDiagnostic(c,d){const v=cardValidation(c,d),rows=diagnosticRows(c,d);modalTitle.textContent=`Diagnosi: ${c.name}`;modalBody.innerHTML=`<div class="validation-summary ${v.errors.length?'bad':'ok'}"><b>${v.errors.length?'ILLEGALE':'LEGALE'}</b><span>${esc(v.errors.length?v.errors.join(' · '):(v.reasons.join(' · ')||'Condizione valida'))}</span></div><div class="diagnostic-list">${rows.map(r=>`<div class="diagnostic-row ${r.pass?'pass':'fail'}"><span>${r.pass?'✓':'×'}</span><div><b>${esc(r.label)}</b><small>${esc(r.detail)}</small></div></div>`).join('')}</div>`;modal.showModal()}
function drawAdminTester(root){
  if(!state.adminTestTribe)state.adminTestTribe=rules.tribes[0]||'';
  if(!state.adminTestKey)state.adminTestKey=keyNames()[0]||'';
  root.innerHTML=`<h2>Collaudo legalità</h2><p class="muted">Cerca una carta, scegli Tribe e Key e osserva ogni passaggio del controllo. Le correzioni vengono salvate subito nel database Admin.</p><div class="form-grid two"><label>Carta<div class="inline"><input id="adminTestName" placeholder="Nome della carta"><button id="adminTestSearch" class="primary">Cerca</button></div></label><label>Tribe<select id="adminTestTribe">${rules.tribes.map(x=>opt(x,state.adminTestTribe)).join('')}</select></label><label>Key<select id="adminTestKey">${keyNames().map(x=>opt(x,state.adminTestKey)).join('')}</select></label></div><section id="adminTestResult" class="top-gap"></section>`;
  adminTestTribe.onchange=e=>{state.adminTestTribe=e.target.value;drawAdminTestResult()};
  adminTestKey.onchange=e=>{state.adminTestKey=e.target.value;drawAdminTestResult()};
  adminTestSearch.onclick=runAdminCardTest;
  adminTestName.onkeydown=e=>{if(e.key==='Enter')runAdminCardTest()};
  drawAdminTestResult();
}
async function runAdminCardTest(){
  const name=adminTestName.value.trim();if(!name)return;
  setBusy(true,'Analizzo la carta…');
  try{const raw=await api(`https://api.scryfall.com/cards/named?fuzzy=${encodeURIComponent(name)}`);state.adminTestCard=simplifyCard(raw);savedCards[state.adminTestCard.id]=state.adminTestCard;persist();drawAdminTestResult()}
  catch(e){adminTestResult.innerHTML=`<p class="error">${esc(e.message)}</p>`}
  finally{setBusy(false)}
}
function adminTestDeck(){return {tribe:state.adminTestTribe,key:state.adminTestKey,colorIdentity:state.adminTestCard?.colorIdentity||[],cards:[],commanders:[]}}
function diagnosticRows(c,d){
  const name=normalizedName(c.name),text=expandedRulesText(c),type=normalizedName(c.type),aliases=tribeTerms(d.tribe),isCreature=type.includes('creature'),key=getKey(d.key),rows=[];
  const push=(label,pass,detail)=>rows.push({label,pass,detail});
  push('Legalità Commander',c.legalities?.commander==='legal',c.legalities?.commander==='legal'?'Carta legale in Commander':`Stato Scryfall: ${c.legalities?.commander||'non disponibile'}`);
  const bracket=cardBracket(c);push('Bracket',bracket<=rules.maxBracket,`Carta: ${bracket} · massimo consentito: ${rules.maxBracket}`);
  push('Game Changer',!(rules.excludeGameChangers&&rules.maxBracket<=2&&c.gameChanger),c.gameChanger?'La carta è segnalata come Game Changer':'Non segnalata come Game Changer');
  const forcedIllegal=rules.illegalOverrides.some(x=>normalizedName(x)===name);push('Esclusione Admin',!forcedIllegal,forcedIllegal?'Carta presente tra le escluse':'Nessuna esclusione manuale');
  const forcedLegal=rules.legalOverrides.some(x=>normalizedName(x)===name);push('Ammissione Admin',forcedLegal,forcedLegal?'Carta ammessa forzatamente':'Nessuna ammissione manuale');
  const evergreen=rules.evergreen.some(x=>normalizedName(x)===name);push('Evergreen',evergreen,evergreen?'Presente nella lista Evergreen':'Non presente nella lista Evergreen');
  const tribeType=isCreature&&aliases.some(a=>new RegExp(`(?:—|\\b)\\s*${escapeRegExp(a)}\\b`,'i').test(c.type));push('Creatura della Tribe',tribeType,tribeType?`Il tipo contiene ${d.tribe}`:`Il tipo non contiene ${d.tribe}`);
  const tribeText=aliases.some(a=>a&&new RegExp(`\\b${escapeRegExp(a)}s?\\b`,'i').test(text));push('Testo che cita la Tribe',tribeText,tribeText?`Trovato uno tra: ${aliases.join(', ')}`:`Nessuno tra: ${aliases.join(', ')}`);
  const choose=!isCreature&&rules.chooseTypePhrases.some(p=>text.includes(normalizedName(p)));push('“Scegli un tipo”',choose,choose?'Trovata una frase speciale':'Nessuna frase speciale trovata');
  const commander=!isCreature&&rules.commanderPhrases.some(p=>text.includes(normalizedName(p)));push('Riferimento al comandante',commander,commander?'Trovato un riferimento al comandante':'Nessun riferimento al comandante');
  const keyMatch=!isCreature&&matchesKey(c,key);push(`Key: ${d.key}`,keyMatch,keyMatch?`Termine o keyword riconosciuta per ${d.key}`:`Nessuna corrispondenza per ${d.key}`);
  const basic=type.includes('basic land');push('Terra base',basic,basic?'Le terre base sono ammesse':'Non è una terra base');
  return rows;
}
function drawAdminTestResult(){
  const root=document.querySelector('#adminTestResult');if(!root)return;const c=state.adminTestCard;
  if(!c){root.innerHTML='<section class="panel empty"><b>Nessuna carta analizzata</b><p class="muted">Cerca una carta per vedere il rapporto completo.</p></section>';return}
  const d=adminTestDeck(),validation=cardValidation(c,d),rows=diagnosticRows(c,d),legal=validation.errors.length===0;
  root.innerHTML=`<div class="admin-test-card"><img src="${cardImage(c)}" alt="${esc(c.name)}"><div><h3>${esc(c.name)}</h3><p class="muted">${esc(c.type)}</p><div class="validation-summary ${legal?'ok':'bad'}"><b>${legal?'LEGALE':'ILLEGALE'}</b><span>${legal?(validation.reasons.join(' · ')||'Condizione valida'):validation.errors.join(' · ')}</span></div><div class="button-row"><button id="testToggleLegal" class="secondary">${rules.legalOverrides.some(x=>normalizedName(x)===normalizedName(c.name))?'Rimuovi ammissione':'Ammetti carta'}</button><button id="testToggleIllegal" class="danger">${rules.illegalOverrides.some(x=>normalizedName(x)===normalizedName(c.name))?'Rimuovi esclusione':'Escludi carta'}</button><button id="testToggleEvergreen" class="secondary">${rules.evergreen.some(x=>normalizedName(x)===normalizedName(c.name))?'Rimuovi Evergreen':'Rendi Evergreen'}</button></div><div class="form-grid two top-gap"><label>Bracket manuale<input id="testBracket" type="number" min="1" max="5" value="${cardBracket(c)}"></label><button id="testSaveBracket" class="secondary align-end">Salva bracket</button></div></div></div><h3>Diagnosi passo per passo</h3><div class="diagnostic-list">${rows.map(r=>`<div class="diagnostic-row ${r.pass?'pass':'fail'}"><span>${r.pass?'✓':'×'}</span><div><b>${esc(r.label)}</b><small>${esc(r.detail)}</small></div></div>`).join('')}</div><details class="top-gap"><summary>Testo analizzato</summary><pre class="oracle-debug">${esc(expandedRulesText(c))}</pre></details>`;
  testToggleLegal.onclick=()=>toggleNamedRule('legalOverrides',c.name);
  testToggleIllegal.onclick=()=>toggleNamedRule('illegalOverrides',c.name);
  testToggleEvergreen.onclick=()=>toggleNamedRule('evergreen',c.name);
  testSaveBracket.onclick=()=>{const value=Number(testBracket.value);if(value>=1&&value<=5){rules.bracketOverrides[c.name]=value;persist();drawAdminTestResult();toast('Bracket salvato')}};
}
function toggleNamedRule(field,name){
  const list=rules[field]||[],norm=normalizedName(name),exists=list.some(x=>normalizedName(x)===norm);
  rules[field]=exists?list.filter(x=>normalizedName(x)!==norm):[...list,name];
  if(field==='legalOverrides'&&!exists)rules.illegalOverrides=rules.illegalOverrides.filter(x=>normalizedName(x)!==norm);
  if(field==='illegalOverrides'&&!exists)rules.legalOverrides=rules.legalOverrides.filter(x=>normalizedName(x)!==norm);
  persist();drawAdminTestResult();toast('Regole aggiornate');
}

function keyEditor(root){root.innerHTML=`<h2>Key</h2><div class="list">${rules.keys.map((k,i)=>`<div class="key-card"><div><b>${esc(k.name)}</b><small>Termini: ${esc(k.terms.join(', '))}</small><small>Keyword: ${esc(k.keywords.join(', '))}</small></div><button class="secondary" data-edit="${i}">Modifica</button><button class="danger" data-del="${i}">Elimina</button></div>`).join('')}</div><button id="addKey" class="primary top-gap">Nuova Key</button>`;root.querySelectorAll('[data-edit]').forEach(b=>b.onclick=()=>openKeyModal(Number(b.dataset.edit)));root.querySelectorAll('[data-del]').forEach(b=>b.onclick=()=>{rules.keys.splice(Number(b.dataset.del),1);persist();drawAdminBody()});addKey.onclick=()=>openKeyModal(-1)}
function openKeyModal(i){const k=i>=0?rules.keys[i]:{name:'',terms:[],keywords:[]};modalTitle.textContent=i>=0?'Modifica Key':'Nuova Key';modalBody.innerHTML=`<label>Nome<input id="kName" value="${esc(k.name)}"></label><label>Termini, separati da virgola<textarea id="kTerms">${esc(k.terms.join(', '))}</textarea></label><label>Keyword collegate<textarea id="kKeywords">${esc(k.keywords.join(', '))}</textarea></label><button id="saveKey" class="primary wide">Salva Key</button>`;modal.showModal();saveKey.onclick=()=>{const item={name:kName.value.trim(),terms:splitCsv(kTerms.value),keywords:splitCsv(kKeywords.value)};if(!item.name)return;if(i>=0)rules.keys[i]=item;else rules.keys.push(item);persist();modal.close();drawAdminBody()}}
function listEditor(root,title,arr,setter){root.innerHTML=`${title?`<h2>${title}</h2>`:''}<div class="list">${arr.map((x,i)=>`<div class="deck-row"><span>${esc(x)}</span><span></span><button class="danger" data-i="${i}">Elimina</button></div>`).join('')}</div><div class="form-grid two top-gap"><input id="newItem" placeholder="Nuovo elemento"><button id="addItem" class="primary">Aggiungi</button></div>`;root.querySelectorAll('[data-i]').forEach(btn=>btn.onclick=()=>{const copy=[...arr];copy.splice(Number(btn.dataset.i),1);setter(copy);persist();drawAdminBody()});addItem.onclick=()=>{const v=newItem.value.trim();if(!v)return;setter([...arr,v]);persist();drawAdminBody()}}
function objectEditor(root,obj,setter,keyLabel,valueLabel){const entries=Object.entries(obj);root.innerHTML=`<div class="list">${entries.map(([k,v],i)=>`<div class="deck-row"><span>${esc(k)}</span><span class="badge">${esc(v)}</span><button class="danger" data-i="${i}">Elimina</button></div>`).join('')}</div><div class="form-grid two top-gap"><input id="objKey" placeholder="${keyLabel}"><input id="objValue" type="number" min="1" max="5" placeholder="${valueLabel}"><button id="objAdd" class="primary">Aggiungi</button></div>`;root.querySelectorAll('[data-i]').forEach(btn=>btn.onclick=()=>{const copy={...obj};delete copy[entries[Number(btn.dataset.i)][0]];setter(copy);persist();drawAdminBody()});objAdd.onclick=()=>{const k=objKey.value.trim(),v=Number(objValue.value);if(!k||!v)return;setter({...obj,[k]:v});persist();drawAdminBody()}}
function renderImport(){setHeader('Importa lista','Riconoscimento automatico di sezioni e comandanti');app.innerHTML=`<section class="panel"><label>Decklist<textarea id="importText" placeholder="Commander
1 Edgar Markov

Deck
1 Sol Ring
1 Command Tower"></textarea></label><div class="form-grid two top-gap"><label>Nome mazzo<input id="importName" value="Mazzo importato"></label><label>Tribe<select id="importTribe">${rules.tribes.map(x=>`<option>${esc(x)}</option>`).join('')}</select></label><label>Key<select id="importKey">${keyNames().map(x=>`<option>${esc(x)}</option>`).join('')}</select></label><label class="check"><input id="autoCommander" type="checkbox" checked> Riconosci automaticamente il comandante</label></div><button id="importBtn" class="primary top-gap">Importa e verifica</button><div id="importResult" class="top-gap"></div></section>`;importBtn.onclick=importDecklist}
async function importDecklist(){const parsed=parseDeckSections(importText.value);if(!parsed.cards.length&&!parsed.commanders.length)return;setBusy(true,'Importo le carte…');const d={id:crypto.randomUUID(),name:importName.value.trim()||'Mazzo importato',commander:'',commanderCard:null,commanders:[],colorIdentity:[],tribe:importTribe.value,key:importKey.value,cards:[],createdAt:Date.now(),updatedAt:Date.now()};const errors=[];for(const line of [...parsed.commanders,...parsed.cards]){try{const c=await api(`https://api.scryfall.com/cards/named?exact=${encodeURIComponent(line.name)}`);const s=simplifyCard(c);const shouldCommander=autoCommander.checked&&(line.section==='commander'||(parsed.commanders.length===0&&isCommander(c)&&d.commanders.length<2));if(shouldCommander)d.commanders.push(s);else d.cards.push({...s,qty:line.qty})}catch{errors.push(line.name)}await delay(70)}syncCommanders(d);state.currentDeck=d;const v=validateDeck(d);importResult.innerHTML=`<p>Comandanti riconosciuti: <b>${d.commanders.length}</b>. Carte nel mazzo: <b>${d.cards.reduce((n,c)=>n+(c.qty||1),0)}</b>.</p>${errors.length?`<p class="error">Non trovate: ${esc(errors.join(', '))}</p>`:''}${v.errors.length?`<p class="error">Problemi rilevati: ${v.errors.length}</p>`:'<p>✓ Nessun errore strutturale rilevato.</p>'}<button id="openImported" class="primary">Apri nel Builder</button>`;openImported.onclick=()=>nav('builder');setBusy(false)}
function parseDeckSections(text){let section='deck';const out={commanders:[],cards:[]};for(const raw of text.split(/\n/)){const line=raw.trim();if(!line)continue;if(/^(commander|commanders|comandante|comandanti)\s*:?$/i.test(line)){section='commander';continue}if(/^(deck|mainboard|mazzo|carte)\s*:?$/i.test(line)){section='deck';continue}if(/^(sideboard|maybeboard|considering)\s*:?$/i.test(line)){section='skip';continue}const p=parseLine(line);if(!p||section==='skip')continue;p.section=section;(section==='commander'?out.commanders:out.cards).push(p)}return out}
function renderPrint(){setHeader('Esporta e stampa','Liste, schede e carte su A4');app.innerHTML=`<section class="panel"><label>Mazzo<select id="printDeck">${decks.map(d=>`<option value="${d.id}">${esc(d.name)}</option>`).join('')}</select></label><div class="form-grid two top-gap"><label>Formato carte<select id="proxySize"><option value="standard">63 × 88 mm</option><option value="fit">Adatta al foglio</option></select></label><label><span>Indicatori di taglio</span><select id="cropMarks"><option value="yes">Visibili</option><option value="no">Nascosti</option></select></label></div><div class="button-row top-gap"><button id="exportTxt" class="primary">Lista testuale</button><button id="printPage" class="secondary">Scheda mazzo</button><button id="printCards" class="primary">Carte pronte per A4</button></div><p class="muted tiny top-gap">La stampa delle carte apre un documento 3×3 per pagina. Nel pannello di stampa del browser puoi scegliere “Salva come PDF”.</p></section>`;exportTxt.onclick=()=>{const d=decks.find(x=>x.id===printDeck.value);if(!d)return;download(`${safeName(d.name)}.txt`,deckText(d),'text/plain')};printPage.onclick=()=>{const d=decks.find(x=>x.id===printDeck.value);if(!d)return;printDeckSheet(d)};printCards.onclick=()=>{const d=decks.find(x=>x.id===printDeck.value);if(!d)return;printProxySheets(d,proxySize.value,cropMarks.value==='yes')}}
function printDeckSheet(d){const stats=['Creature','Artifact','Enchantment','Instant','Sorcery','Planeswalker','Battle','Land'].map(t=>`<li>${typeIt(t)}: ${countContainsType(d,t)}</li>`).join('');const validation=validateDeck(d);const w=open('','_blank');w.document.write(`<!doctype html><meta charset="utf-8"><title>${esc(d.name)}</title><style>body{font:14px system-ui;margin:24px;color:#111}h1{margin-bottom:4px}.meta{color:#555}.cols{columns:2}.errors{padding:10px;background:#fee;border:1px solid #c88}@media print{button{display:none}}</style><h1>${esc(d.name)}</h1><p class="meta">Comandanti: ${esc((d.commanders||[]).map(c=>c.name).join(' + ')||d.commander||'—')} · Tribe: ${esc(d.tribe)} · Key: ${esc(d.key)} · Regole ${esc(rules.version)}</p>${validation.errors.length?`<div class="errors">${validation.errors.map(x=>`<div>⚠ ${esc(x)}</div>`).join('')}</div>`:'<p>✓ Mazzo valido</p>'}<h2>Statistiche</h2><ul>${stats}</ul><h2>Lista</h2><pre class="cols">${esc(deckText(d))}</pre><button onclick="print()">Stampa / Salva PDF</button>`);w.document.close()}
function printProxySheets(d,size='standard',marks=true){const cards=[];for(const cmd of (d.commanders||[]))cards.push(cmd);for(const c of d.cards)for(let i=0;i<(c.qty||1);i++)cards.push(c);if(!cards.length){alert('Il mazzo non contiene carte da stampare.');return}const mark=marks?'outline:0.2mm dashed #777;':'outline:none;';const dimensions=size==='standard'?'width:63mm;height:88mm;':'width:calc((210mm - 16mm)/3);height:calc((297mm - 16mm)/3);';const html=cards.map((c,i)=>`<div class="proxy"><img src="${cardImage(c)}" alt="${esc(c.name)}"><span>${esc(c.name)}</span></div>`).join('');const w=open('','_blank');w.document.write(`<!doctype html><html><head><meta charset="utf-8"><title>${esc(d.name)} – Carte</title><style>@page{size:A4;margin:8mm}*{box-sizing:border-box}body{margin:0;font-family:system-ui;background:#ddd}.sheet{display:grid;grid-template-columns:repeat(3,63mm);grid-auto-rows:88mm;gap:0;justify-content:center;align-content:start}.proxy{${dimensions}${mark}position:relative;overflow:hidden;break-inside:avoid}.proxy img{width:100%;height:100%;object-fit:fill;display:block}.proxy span{display:none}@media screen{body{padding:8mm}.sheet{background:white;margin:auto;width:210mm;min-height:297mm;padding:8mm;box-shadow:0 2px 16px #777}}@media print{body{background:white}.sheet{display:contents}.proxy:nth-child(9n+1){break-before:page}}</style></head><body><main class="sheet">${html}</main><script>window.addEventListener('load',()=>setTimeout(()=>window.print(),500))<\/script></body></html>`);w.document.close()}
function renderSettings(){setHeader('Impostazioni','Backup e dati');app.innerHTML=`<section class="panel"><h2>Preferenze</h2><label class="check"><input id="autosavePref" type="checkbox" ${prefs.autosave?'checked':''}> Salvataggio automatico del mazzo</label><label class="top-gap">Visualizzazione catalogo<select id="catalogViewPref"><option value="grid" ${prefs.catalogView==='grid'?'selected':''}>Griglia</option><option value="list" ${prefs.catalogView==='list'?'selected':''}>Lista compatta</option></select></label></section><section class="panel"><h2>Backup</h2><div class="button-row"><button id="backupBtn" class="primary">Esporta JSON</button><label class="secondary file-label">Importa JSON<input id="restoreFile" type="file" accept="application/json" hidden></label><button id="resetBtn" class="danger">Ripristina</button></div></section>`;autosavePref.onchange=e=>{prefs.autosave=e.target.checked;persist()};catalogViewPref.onchange=e=>{prefs.catalogView=e.target.value;persist()};backupBtn.onclick=()=>download('commander-armies-backup.json',JSON.stringify({decks,rules,favorites,collection,savedCards,prefs},null,2),'application/json');restoreFile.onchange=async e=>{try{const data=JSON.parse(await e.target.files[0].text());decks=data.decks||[];rules=normalizeRules(data.rules||DEFAULT_RULES);favorites=data.favorites||[];collection=data.collection||{};savedCards=data.savedCards||{};prefs=data.prefs||prefs;persist();toast('Backup importato')}catch{alert('Backup non valido')}};resetBtn.onclick=()=>{if(confirm('Eliminare tutti i dati locali?')){Object.values(STORAGE).forEach(k=>localStorage.removeItem(k));location.reload()}}}
async function showPrintings(c,target={kind:'catalog'}){modalTitle.textContent=`Edizioni di ${c.name}`;modalBody.innerHTML='<p class="muted">Caricamento edizioni e prezzi…</p>';modal.showModal();try{const data=await api(`https://api.scryfall.com/cards/search?order=released&unique=prints&q=${encodeURIComponent(`oracleid:${c.id}`)}`);const prints=(data.data||[]).map(simplifyCard).filter(x=>x.image);modalBody.innerHTML=`<div class="printing-grid">${prints.map((x,i)=>`<button class="printing-option" data-print="${i}"><img src="${cardImage(x)}"><b>${esc(x.setName||x.set)}</b><small>${esc(x.set)} #${esc(x.collectorNumber)} · ${formatPrice(cardPrice(x))}</small></button>`).join('')}</div>`;modalBody.querySelectorAll('[data-print]').forEach(b=>b.onclick=()=>{const chosen=prints[Number(b.dataset.print)];if(target.kind==='commander'){state.currentDeck.commanders[target.index]=chosen;syncCommanders(state.currentDeck);renderBuilder()}else if(target.kind==='deck'){const i=state.currentDeck.cards.findIndex(x=>x.id===c.id);if(i>=0)state.currentDeck.cards[i]={...chosen,qty:state.currentDeck.cards[i].qty||1};drawDeck()}else{const i=state.results.findIndex(x=>x.id===c.id);if(i>=0)state.results[i]=chosen;drawCatalog()}autoSave();modal.close();toast('Edizione selezionata')})}catch(e){modalBody.innerHTML=`<p class="error">${esc(e.message)}</p>`}}
function showCard(c){modalTitle.textContent=c.name;modalBody.innerHTML=`<img src="${cardImage(c)}" alt="${esc(c.name)}"><p><b>${esc(c.type)}</b></p><p>${esc(c.oracle||'')}</p><p>Edizione: <b>${esc(c.setName||c.set||'—')}</b> ${esc(c.collectorNumber||'')} · Prezzo: <b>${formatPrice(cardPrice(c))}</b></p><p>Bracket applicato: <b>${cardBracket(c)}</b> / massimo ${rules.maxBracket}</p><p>${legalReasons(c,state.currentDeck||{tribe:'',key:''}).map(r=>`<span class="badge">${esc(r)}</span>`).join(' ')||'<span class="error">Nessuna condizione Armies soddisfatta</span>'}</p>`;modal.showModal()}
function simplifyCard(c){const face=c.card_faces?.[0];return{id:c.oracle_id||c.id,printingId:c.id,name:c.name,type:allType(c),oracle:allOracle(c),manaCost:c.mana_cost||face?.mana_cost||'',cmc:c.cmc||0,colorIdentity:c.color_identity||[],keywords:c.keywords||[],gameChanger:!!c.game_changer,legalities:c.legalities||{},image:c.image_uris?.normal||face?.image_uris?.normal||'',scryfallUri:c.scryfall_uri||'',set:c.set?.toUpperCase()||'',setName:c.set_name||'',collectorNumber:c.collector_number||'',releasedAt:c.released_at||'',prices:c.prices||{},finishes:c.finishes||[]}}
function allType(c){return c.type_line||c.card_faces?.map(f=>f.type_line).join(' // ')||''}function allOracle(c){return c.oracle_text||c.card_faces?.map(f=>f.oracle_text||'').join(' // ')||''}function cardImage(c){return c.image||placeholder()}function placeholder(){return 'data:image/svg+xml;charset=UTF-8,'+encodeURIComponent(`<svg xmlns="http://www.w3.org/2000/svg" width="488" height="680"><rect width="100%" height="100%" fill="#242428"/><text x="50%" y="50%" fill="#aaa" text-anchor="middle" font-family="sans-serif">Carta</text></svg>`)}
async function api(url){if(!navigator.onLine)throw new Error('Connessione assente: la ricerca Scryfall richiede Internet.');let r;try{r=await fetch(url,{headers:{Accept:'application/json'}})}catch{throw new Error('Impossibile raggiungere Scryfall. Controlla la connessione e riprova.')}let data={};try{data=await r.json()}catch{}if(!r.ok)throw new Error(data.details||`Errore Scryfall (${r.status})`);return data}
function setBusy(on,msg=''){state.loading=on;pageSubtitle.textContent=on?msg:(state.page==='builder'?`${state.currentDeck?.tribe||''} · ${state.currentDeck?.key||''}`:'');document.querySelectorAll('button').forEach(b=>b.disabled=on)}
function toast(msg){pageSubtitle.textContent=msg;setTimeout(()=>{if(state.page==='builder')pageSubtitle.textContent=`${state.currentDeck?.tribe||''} · ${state.currentDeck?.key||''}`},1200)}
function parseLine(line){const m=line.trim().match(/^(\d+)x?\s+(.+?)(?:\s+\([A-Z0-9]+\)\s+\d+)?$/i);return m?{qty:Number(m[1]),name:m[2].trim()}:null}function splitCsv(s){return s.split(',').map(x=>x.trim()).filter(Boolean)}function quote(s){return `"${String(s).replaceAll('"','')}"`}function delay(ms){return new Promise(r=>setTimeout(r,ms))}
function deckText(d){return `${(d.commanders||[]).map(c=>`1 ${c.name} (${c.set||''}) ${c.collectorNumber||''}`.trim()).join('\n')}${(d.commanders||[]).length?'\n\n':''}${d.cards.map(c=>`${c.qty||1} ${c.name}${c.set?` (${c.set}) ${c.collectorNumber||''}`:''}`).join('\n')}`}
function cardPrice(c){return Number(c?.prices?.eur||c?.prices?.eur_foil||c?.prices?.usd||0)||0}function deckPrice(d){return [...(d.commanders||[]),...d.cards].reduce((n,c)=>n+cardPrice(c)*(c.qty||1),0)}function formatPrice(n){return n?new Intl.NumberFormat('it-IT',{style:'currency',currency:'EUR'}).format(n):'—'}function safeName(s){return s.replace(/[^a-z0-9-_]+/gi,'-')}function download(name,text,type){const a=document.createElement('a');a.href=URL.createObjectURL(new Blob([text],{type}));a.download=name;a.click();setTimeout(()=>URL.revokeObjectURL(a.href),500)}
function opt(x,v){return `<option ${x===v?'selected':''}>${esc(x)}</option>`}function typeIt(t){return ({All:'Tutto',Creature:'Creature',Planeswalker:'Planeswalker',Artifact:'Artefatti',Enchantment:'Incantesimi',Instant:'Istantanei',Sorcery:'Stregonerie',Battle:'Battaglie',Land:'Terre'})[t]||t}function esc(v=''){return String(v).replace(/[&<>'"]/g,s=>({'&':'&amp;','<':'&lt;','>':'&gt;',"'":'&#39;','"':'&quot;'}[s]))}
function updateNetworkStatus(){document.body.classList.toggle('offline',!navigator.onLine);if(!navigator.onLine)pageSubtitle.textContent='Offline · mazzi disponibili, ricerca carte disattivata'}
window.addEventListener('online',()=>{updateNetworkStatus();toast('Connessione ripristinata')});window.addEventListener('offline',updateNetworkStatus);updateNetworkStatus();
if('serviceWorker' in navigator){navigator.serviceWorker.getRegistrations().then(rs=>rs.forEach(r=>r.unregister()));} if('caches' in window){caches.keys().then(ks=>ks.forEach(k=>caches.delete(k)));}
function initV9(){document.body.classList.add('v9');const nav=document.createElement('nav');nav.className='bottom-nav';nav.innerHTML=`<button data-nav="home">⌂<span>Home</span></button><button data-nav="builder">🛠<span>Builder</span></button><button data-nav="decks">🗂<span>Mazzi</span></button><button data-nav="archive">🃏<span>Archivio</span></button><button data-nav="rules">📖<span>Regole</span></button>`;document.body.appendChild(nav);nav.querySelectorAll('[data-nav]').forEach(b=>b.onclick=()=>navPage(b.dataset.nav));window.addEventListener('beforeunload',()=>{if(prefs.autosave&&state.currentDeck)saveCurrentDeck();persist()});}
function navPage(page){if(page==='builder'&&!state.currentDeck)newDeck();nav(page);updateBottomNav()}
const originalRender=render;render=function(){originalRender();updateBottomNav()};
function updateBottomNav(){document.querySelectorAll('.bottom-nav [data-nav]').forEach(b=>b.classList.toggle('active',b.dataset.nav===state.page))}
initV9();render();
